import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.C5xPiHZ1.js";import"./chunks/assets.C2lZWGyA.js";var i=JSON.parse(`{"title":"1.1.5 PET/SPECT: Metabolism & Function","description":"PET coincidence detection, tracers, and a short SPECT overview","frontmatter":{"title":"1.1.5 PET/SPECT: Metabolism & Function","description":"PET coincidence detection, tracers, and a short SPECT overview"},"headers":[],"relativePath":"en/guide/ch01/01-modalities/05-pet.md","filePath":"en/guide/ch01/01-modalities/05-pet.md"}`),a={name:`en/guide/ch01/01-modalities/05-pet.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="_1-1-5-pet-spect-metabolism-function" tabindex="-1">1.1.5 PET/SPECT: Metabolism &amp; Function <a class="header-anchor" href="#_1-1-5-pet-spect-metabolism-function" aria-label="Permalink to “1.1.5 PET/SPECT: Metabolism &amp; Function”">​</a></h1><p>PET and SPECT are <strong>functional imaging</strong> modalities: beyond anatomy, they visualize metabolism, perfusion, and receptor distribution using radioactive tracers.</p><hr><h2 id="pet-coincidence-detection-and-lor" tabindex="-1">PET: coincidence detection and LOR <a class="header-anchor" href="#pet-coincidence-detection-and-lor" aria-label="Permalink to “PET: coincidence detection and LOR”">​</a></h2><p>PET relies on positron annihilation:</p><ol><li>Inject a positron-emitting tracer (e.g., <strong>¹⁸F-FDG</strong>)</li><li>Positron annihilates with an electron</li><li>Two <strong>511 keV</strong> photons are emitted ~180° apart</li><li>Coincidence detection forms a <strong>Line of Response (LOR)</strong></li></ol><p>Common tracers include <strong>¹⁸F-FDG</strong> and <strong>⁶⁸Ga-PSMA</strong>.</p><hr><h2 id="pet-ct-pet-mri" tabindex="-1">PET-CT / PET-MRI <a class="header-anchor" href="#pet-ct-pet-mri" aria-label="Permalink to “PET-CT / PET-MRI”">​</a></h2><p>Hybrid imaging combines:</p><ul><li>anatomical localization (CT/MRI)</li><li>attenuation correction and improved quantification</li></ul><p><img src="/med-imaging-primer/images/ch01/pet-ct-scanner.jpg" alt="PET-CT Scanner"><em>A modern PET-CT scanner</em></p><hr><h2 id="spect-single-photons-collimator" tabindex="-1">SPECT: single photons + collimator <a class="header-anchor" href="#spect-single-photons-collimator" aria-label="Permalink to “SPECT: single photons + collimator”">​</a></h2><p>SPECT detects <strong>single gamma photons</strong> and uses a <strong>collimator</strong> to infer direction, trading sensitivity for directionality. It is widely used due to accessibility and mature clinical workflows (e.g., bone imaging, perfusion studies).</p>`,15)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};